class Solution:
    def findDuplicate(self, paths: List[str]) -> List[List[str]]:
        mp = defaultdict(list)
        for p in paths:
            parts = p.split()
            root = parts[0]
            for f in parts[1:]:
                i = f.index('(')
                mp[f[i+1:-1]].append(root + '/' + f[:i])
        return [[v[0]]+v for v in mp.values() if len(v)>1]

